tabela = [
    [20, 22],
    [18, 15],
]

for i, linha in enumerate(tabela):
    for j, valor in enumerate(linha):
        print(f"Linha {i}, Coluna {j}: {valor}")

vendas = [
    [10, 20, 30],  # semana 0
    [5, 5, 5],     # semana 1
]

for i, semana in enumerate(vendas):
    total = 0
    for v in semana:
        total += v
    print(f"Semana {i}: total {total}")

vendas = [
    [10, 20, 30],
    [5, 5, 5],
]

for i, semana in enumerate(vendas):
    print(f"Semana {i}: total {sum(semana)}")

producao = [
    [100, 100, 100],
    [100,   0, 100],
    [100, 100, 100],
]

falhas = 0
for i, semana in enumerate(producao):
    for j, qtd in enumerate(semana):
        if qtd == 0:
            print(f"ALERTA: falha na linha {i}, coluna {j}")
            falhas += 1

print(f"Total de falhas: {falhas}")
